#include <stdio.h>
int main() {
    int T, N, W, Q, Posi, Coli, i, j, count;
    int A[100005];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &W);
        for (i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        scanf("%d", &Q);
        while (Q--) {
            scanf("%d %d", &Posi, &Coli);
            A[Posi - 1] = Coli;
            count = 0;
            for (i = 0; i <= N - W; i++) {
                for (j = 0; j < W; j++) {
                    if (A[i] != A[i + j]) break;
                }
                if (j == W) count++;
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

