code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int W = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int Q = sc.nextInt();
            while (Q-- > 0) {
                int Posi = sc.nextInt();
                int Coli = sc.nextInt();
                A[Posi - 1] = Coli;
                int count = 0;
                for (int i = 0; i <= N - W; i++) {
                    boolean flag = true;
                    for (int j = 0; j < W; j++) {
                        if (A[i] != A[i + j]) {
                            flag = false;
                            break;
                        }
                    }
                    if (flag) count++;
                }
                System.out.println(count);
            }
        }
    }
}

